function transactionRow(t){
  const isIn=t.type==='in';const isInvoice=t.type==='invoice';const cls=isIn?'amount-green':'amount-red';const title=isInvoice?'فاکتور خرید ثبت شد':(isIn?'پول گرفتم':'پول دادم');const badge=isInvoice?'فاکتور':(isIn?'دریافت':'پرداخت');const badgeCls=isIn?'green':'red';const extra=isInvoice&&t.invoiceNo?` · شماره فاکتور ${escapeHtml(t.invoiceNo)}`:'';
  const actions=[];if(isInvoice)actions.push(`<button class="btn secondary small" onclick="openInvoiceView('${escapeHtml(t.invoiceId||'')}','${escapeHtml(t.invoiceNo||'')}')">مشاهده فاکتور</button>`);if(canEditRecord(t)){if(isInvoice){actions.push(`<button class="btn soft small" onclick="requestEditInvoice('${escapeHtml(t.invoiceId||'')}')">ویرایش فاکتور</button>`);actions.push(`<button class="btn soft-danger small" onclick="requestDeleteInvoice('${escapeHtml(t.invoiceId||'')}')">حذف فاکتور</button>`)}else{actions.push(`<button class="btn secondary small" onclick="requestEditTransaction('${escapeHtml(t.id||'')}')">ویرایش</button>`);actions.push(`<button class="btn soft-danger small" onclick="requestDeleteTransaction('${escapeHtml(t.id||'')}')">حذف</button>`)}}
  const actionHtml=actions.length?`<div class="record-actions">${actions.join('')}</div>`:'';
  const partyPrefix=isInvoice?'':escapeHtml(contactName(t.contactId))+' · ';return `<div class="transaction"><div><div class="${cls}">${money(t.amount)} ${title}</div><div class="row-sub">${partyPrefix}${escapeHtml(t.date||'')} ${escapeHtml(t.time||'')} ${t.method?' · '+escapeHtml(t.method):''}${extra}</div><div class="row-sub">${escapeHtml(t.note||'')}</div>${actionHtml}</div><span class="badge ${badgeCls}">${badge}</span></div>`
}
