let invoiceDraft=[];
let invoiceEditingLineIndex=-1;
function englishDigits(value){return String(value??'').replace(/[۰-۹]/g,d=>'۰۱۲۳۴۵۶۷۸۹'.indexOf(d)).replace(/[٠-٩]/g,d=>'٠١٢٣٤٥٦٧٨٩'.indexOf(d))}
function groupedInputValue(value,allowDecimal=false){let raw=englishDigits(value).replace(/[٬,\s]/g,'');raw=allowDecimal?raw.replace(/[^0-9.]/g,''):raw.replace(/[^0-9]/g,'');if(allowDecimal){const first=raw.indexOf('.');if(first>=0)raw=raw.slice(0,first+1)+raw.slice(first+1).replace(/\./g,'')}let parts=raw.split('.');let intPart=parts[0]||'';if(intPart)intPart=intPart.replace(/^0+(?=\d)/,'').replace(/\B(?=(\d{3})+(?!\d))/g,',');return allowDecimal&&parts.length>1?intPart+'.'+parts[1]:intPart}
function formatGroupedInput(input,allowDecimal=false){if(input)input.value=groupedInputValue(input.value,allowDecimal)}
function nval(v){return Number(englishDigits(v).replace(/[٬,]/g,''))||0}
function itemById(id){return state.items.find(x=>String(x.id)===String(id))}
