  let list=adminFinancialRecords().filter(t=>{
    const owner=recordOwnerUser(t);const ownerMatch=!userId||String(owner?.id||t.ownerUserId||'')===String(userId);const typeMatch=!type||t.type===type;const hay=[recordOwnerName(t),contactName(t.contactId),t.amount,t.note,t.method,t.date,t.time,t.invoiceNo].join(' ').toLowerCase();return ownerMatch&&typeMatch&&(!q||hay.includes(q))
  }).sort((a,b)=>String((b.date||'')+(b.time||'')).localeCompare(String((a.date||'')+(a.time||''))));
  const invoiceRows=list.filter(t=>t.type==='invoice'),inRows=list.filter(t=>t.type==='in'),outRows=list.filter(t=>t.type==='out');
